CREATE TABLE IF NOT EXISTS roles (id INTEGER PRIMARY KEY, name TEXT UNIQUE NOT NULL, title TEXT NOT NULL, created_at TEXT);
CREATE TABLE IF NOT EXISTS users (id INTEGER PRIMARY KEY, username TEXT UNIQUE NOT NULL, full_name TEXT NOT NULL, email TEXT UNIQUE NOT NULL, password_hash TEXT NOT NULL, role_id INTEGER NOT NULL, is_active INTEGER DEFAULT 1, created_at TEXT, last_login_at TEXT, FOREIGN KEY(role_id) REFERENCES roles(id));
CREATE TABLE IF NOT EXISTS educational_programs (id INTEGER PRIMARY KEY, name TEXT NOT NULL, education_level TEXT NOT NULL, department TEXT NOT NULL, duration_months INTEGER NOT NULL, description TEXT, created_at TEXT);
CREATE TABLE IF NOT EXISTS educational_services (id INTEGER PRIMARY KEY, program_id INTEGER NOT NULL, name TEXT NOT NULL, study_format TEXT NOT NULL, region TEXT NOT NULL, current_price REAL NOT NULL, is_active INTEGER DEFAULT 1, created_at TEXT, FOREIGN KEY(program_id) REFERENCES educational_programs(id));
CREATE TABLE IF NOT EXISTS price_history (id INTEGER PRIMARY KEY, service_id INTEGER NOT NULL, year INTEGER NOT NULL, price REAL NOT NULL, discount_percent REAL DEFAULT 0, student_count INTEGER DEFAULT 0, created_at TEXT, FOREIGN KEY(service_id) REFERENCES educational_services(id));
CREATE TABLE IF NOT EXISTS demand_indicators (id INTEGER PRIMARY KEY, service_id INTEGER NOT NULL, year INTEGER NOT NULL, demand_index REAL NOT NULL, salary_index REAL NOT NULL, advertising_spend REAL DEFAULT 0, created_at TEXT, FOREIGN KEY(service_id) REFERENCES educational_services(id));
CREATE TABLE IF NOT EXISTS competitor_prices (id INTEGER PRIMARY KEY, service_id INTEGER NOT NULL, competitor_name TEXT NOT NULL, year INTEGER NOT NULL, price REAL NOT NULL, source TEXT, created_at TEXT, FOREIGN KEY(service_id) REFERENCES educational_services(id));
CREATE TABLE IF NOT EXISTS dataset_files (id INTEGER PRIMARY KEY, filename TEXT NOT NULL, original_name TEXT NOT NULL, row_count INTEGER DEFAULT 0, status TEXT, description TEXT, uploaded_at TEXT);
CREATE TABLE IF NOT EXISTS forecast_results (id INTEGER PRIMARY KEY, service_id INTEGER, created_by INTEGER, year INTEGER NOT NULL, region TEXT NOT NULL, education_level TEXT NOT NULL, program_name TEXT NOT NULL, study_format TEXT NOT NULL, input_payload TEXT, predicted_price REAL NOT NULL, recommendation TEXT, created_at TEXT, FOREIGN KEY(service_id) REFERENCES educational_services(id), FOREIGN KEY(created_by) REFERENCES users(id));
CREATE TABLE IF NOT EXISTS report_files (id INTEGER PRIMARY KEY, created_by INTEGER, filename TEXT NOT NULL, report_type TEXT NOT NULL, file_path TEXT NOT NULL, created_at TEXT, FOREIGN KEY(created_by) REFERENCES users(id));
CREATE TABLE IF NOT EXISTS system_settings (id INTEGER PRIMARY KEY, key TEXT UNIQUE NOT NULL, value TEXT NOT NULL, description TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS feedback_messages (id INTEGER PRIMARY KEY, created_by INTEGER, full_name TEXT NOT NULL, email TEXT NOT NULL, subject TEXT NOT NULL, message TEXT NOT NULL, status TEXT DEFAULT 'новое', created_at TEXT, FOREIGN KEY(created_by) REFERENCES users(id));
